#include <vector>
#include <unordered_map>
#include <priority_queue>
#include <algorithm>

using namespace std;

int find(vector<int>& parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    vector<int> parent(c + 1, 0);
    vector<int> rank(c + 1, 1);
    for (int i = 1; i <= c; ++i) {
        parent[i] = i;
    }

    for (auto& conn : connections) {
        int u = conn[0];
        int v = conn[1];
        int root_u = find(parent, u);
        int root_v = find(parent, v);
        if (root_u != root_v) {
            if (rank[root_u] > rank[root_v]) {
                parent[root_v] = root_u;
            } else {
                parent[root_u] = root_v;
                if (rank[root_u] == rank[root_v]) {
                    rank[root_v]++;
                }
            }
        }
    }

    unordered_map<int, vector<int>> component_stations;
    for (int i = 1; i <= c; ++i) {
        int root = find(parent, i);
        component_stations[root].push_back(i);
    }

    unordered_map<int, priority_queue<int, vector<int>, greater<int>>> component_heaps;
    for (auto& [root, stations] : component_stations) {
        priority_queue<int, vector<int>, greater<int>> pq;
        for (int station : stations) {
            pq.push(station);
        }
        component_heaps[root] = pq;
    }

    vector<bool> online(c + 1, true);
    vector<long long> res;

    for (auto& query : queries) {
        int type = query[0];
        int x = query[1];
        if (type == 1) {
            if (online[x]) {
                res.push_back(x);
            } else {
                int root = find(parent, x);
                while (!component_heaps[root].empty() && !online[component_heaps[root].top()]) {
                    component_heaps[root].pop();
                }
                if (component_heaps[root].empty()) {
                    res.push_back(-1);
                } else {
                    res.push_back(component_heaps[root].top());
                }
            }
        } else {
            online[x] = false;
        }
    }

    return res;
}

