import heapq
from collections import defaultdict

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    class DSU:
        def __init__(self, size):
            self.parent = list(range(size + 1))  # 1-based indexing
            self.rank = [1] * (size + 1)
        def find(self, x):
            if self.parent[x] != x:
                self.parent[x] = self.find(self.parent[x])
            return self.parent[x]
        def union(self, x, y):
            x_root = self.find(x)
            y_root = self.find(y)
            if x_root == y_root:
                return
            if self.rank[x_root] < self.rank[y_root]:
                self.parent[x_root] = y_root
            else:
                self.parent[y_root] = x_root
                if self.rank[x_root] == self.rank[y_root]:
                    self.rank[x_root] += 1
    dsu = DSU(c)
    for u, v in connections:
        dsu.union(u, v)
    component_stations = defaultdict(list)
    for i in range(1, c + 1):
        root = dsu.find(i)
        component_stations[root].append(i)
    component_heaps = defaultdict(list)
    for root, stations in component_stations.items():
        for station in stations:
            heapq.heappush(component_heaps[root], station)
    online = [True] * (c + 1)
    res = []
    for query in queries:
        type_q, x = query
        if type_q == 1:
            if online[x]:
                res.append(x)
            else:
                root = dsu.find(x)
                while component_heaps[root] and not online[component_heaps[root][0]]:
                    heapq.heappop(component_heaps[root])
                if component_heaps[root]:
                    res.append(component_heaps[root][0])
                else:
                    res.append(-1)
        else:
            online[x] = False
    return res
